module top_module (
    input o,
    input c,
    input q,
    output reg invalid_z
);
    always @(*) begin
        case ({o, c, q})
            3'b010: invalid_z = 1'b1;
            3'b101: invalid_z = 1'b1;
            3'b110: invalid_z = 1'b0;
            3'b111: invalid_z = 1'b1;
            3'b000: invalid_z = 1'b1;
            3'b001: invalid_z = 1'b0;
            3'b011: invalid_z = 1'b1;
            3'b100: invalid_z = 1'b1;
        endcase
    end
endmodule
